import { createContext, useContext, useContextSelector } from 'use-context-selector';
import { createContextHook } from '@universe-design/react-utilities';
import type { DateCalendarUIProps, InteractivePanelProps } from './interface';
import type moment from 'moment';
import type { MODE } from '../../interface';

export type CalendarUIContextType<DateType> = Required<
  Omit<InteractivePanelProps<DateType>, 'selectedRange'> &
    Pick<
      DateCalendarUIProps<DateType>,
      'previewDate' | 'startOfWeek' | 'noOutOfViewWeek' | 'pickerValue' | 'onContentMouseEnter' | 'onContentMouseLeave'
    >
> &
  Pick<DateCalendarUIProps<DateType>, 'cellRenderer' | 'selectedRange' | 'hideWeekNumbers' | 'janX'> & {
    shouldCellDisabled: (date: DateType, mode: MODE) => boolean;
  };

const {
  Provider: CalendarUIProvider,
  useContext: useDateCalendarUIContext,
  useContextSelector: useCalendarUIContextSelector,
} = createContextHook<CalendarUIContextType<moment.Moment>>('CalendarUIContext', {
  strict: true,
  customizedContextMethods: {
    createContext,
    useContext,
    useContextSelector,
  },
});

export { CalendarUIProvider, useDateCalendarUIContext, useCalendarUIContextSelector };
